"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[1286],{89408:e=>{e.exports=JSON.parse('{"functions":[{"name":"connect","desc":"Joins (or starts) the shared toolbar identified by `toolbarId`. The\\ncaller\'s `ourPrivateButtons` are buttons only this peer knows about;\\n`ourSharedButtons` are advertised to every other peer via the\\nInterposer protocol and clicks are routed back here.","params":[{"name":"scope","desc":"Cleanup scope for connections, threads, and child scopes.","lua_type":"{ unknown }"},{"name":"plugin","desc":"Used by the underlying [OwnedToolbar].","lua_type":"Plugin"},{"name":"devEnvName","desc":"Identifier for [IsLocalDev]/[ElttobLog].","lua_type":"string"},{"name":"interposer","desc":"Already-connected Interposer.","lua_type":"Interposer.InterposerApi"},{"name":"leader","desc":"Already-connected Leader.","lua_type":"Leader.LeaderApi"},{"name":"protocolNamespace","desc":"Stable namespace for the underlying Interposer protocol id (e.g. `\\"@my-suite/SharedToolbar\\"`). Plugins sharing both `protocolNamespace` and `toolbarId` see each other.","lua_type":"string"},{"name":"toolbarId","desc":"Stable identifier for this toolbar; every peer must agree on it.","lua_type":"string"},{"name":"toolbarTitle","desc":"Human-readable name shown in Studio.","lua_type":"string"},{"name":"thisStableId","desc":"Stable identifier for this peer; usually the plugin\'s package name.","lua_type":"string"},{"name":"ourPrivateButtons","desc":"","lua_type":"{ [string]: ButtonSpec }"},{"name":"ourSharedButtons","desc":"","lua_type":"{ [string]: ButtonSpec }"}],"returns":[{"desc":"","lua_type":"SharedToolbarApi"}],"function_type":"static","source":{"line":99,"path":"plugin/shared-toolbar/init.luau"}}],"properties":[],"types":[],"name":"SharedToolbar","desc":"Cross-plugin shared toolbar built on top of [Interposer] and\\n[Leader]. Every cooperating plugin calls [SharedToolbar.connect] with\\nthe same `toolbarId`; the leader builds a single `PluginToolbar`\\nthat mirrors every peer\'s buttons, and click/state events are\\nforwarded back to the originating peer.\\n\\nSlight deviation from upstream: drops Fusion entirely. State lives in\\nplain values that get re-applied to the underlying [OwnedToolbar]\\nwhen they change, and lifetime is tracked through `{ unknown }`\\nscopes cleaned up via [DoCleanup].","source":{"line":19,"path":"plugin/shared-toolbar/init.luau"}}')}}]);